$$, $$2fd2b4770b4bc1645cc2069a0df1325acab2fcb9fdfc508929ee4db4706c049d$$, $${"A": "f904db9fefedf1ab0ae57f7e18daafecab35d72fdb47b15106eef34c830d6a2c", "D": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "E": "ebc1b3830ea8bfa0ecedeeabc8838bed7e60913a72b86255f8fb5156bbf018fd"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, 281, $$2026-05-07T23:56:37.011952+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0607139A$$, 2026, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Improved Turbine Engine Program (ITEP). ITEP develops, tests, qualifies, and
integrates the next generation turboshaft engine on Black Hawk and Apache aircraft. The Improved Turbine Engine (ITE) replaces the existing T700 engine design
originated in the 1970s and meets the operational requirement of 6,000 feet pressure altitude and 95 degrees (6K/95). The ITE will fit inside the existing engine bays
of the Black Hawk and Apache Helicopters and provides a significant power enhancement of up to fifty percent (total of 3,000 class shaft horsepower) with increased
fuel efficiency. Additional benefits include improved design life, enhanced reliability, lower maintenance cost and restored capability lost due to aircraft weight growth
without an increase to the logistics footprint. The program consists of systems engineering and program management, detailed design engineering, design assurance,
hardware manufacturing and testing, component and module level development and testing, system level testing and qualification, and platform integration and
qualification.$$, $$This funding line is a key enabler of the Army Modernization Priorities in support of the Improved Turbine Engine Program (ITEP). ITEP develops, tests, qualifies, and
integrates the next generation turboshaft engine on Black Hawk and Apache aircraft. The Improved Turbine Engine (ITE) replaces the existing T700 engine design
originated in the 1970s and meets the operational requirement of 6,000 feet pressure altitude and 95 degrees (6K/95). The ITE will fit inside the existing engine bays
of the Black Hawk and Apache Helicopters and provides a significant power enhancement of up to fifty percent (total of 3,000 class shaft horsepower) with increased
fuel efficiency. Additional benefits include improved design life, enhanced reliability, lower maintenance cost and restored capability lost due to aircraft weight growth
without an increase to the logistics footprint. The program consists of systems engineering and program management, detailed design engineering, design assurance,
hardware manufacturing and testing, component and module level development and testing, system level testing and qualification, and platform integration and
qualification.

B. Accomplishments/Planned Programs ($ in Millions)                                                                                      FY 2024            FY 2025     FY 2026
Title: ITEP                                                                                                                                182.204             67.029          -
Description: ITEP - a multi-platform turbine engine development required across existing Army aircraft to fill the capability gaps
for Army Aviation Operations

FY 2025 Plans:
FY 2025 continues Preliminary Flight Rating (PFR) testing, continues detailed test planning, provides for delivery of flight test
engines and continues Black Hawk aircraft testing activities. Program achieved First Flight on 13 May 2025.
FY 2025 to FY 2026 Increase/Decrease Statement:
The decrease in FY 2026 in the Improved Turbine Engine Program supports the Army Transformation Initiative.
